// CustomerService - Validar productos con WebClient
package com.paymentchange.customer.services;

import com.paymentchange.customer.entities.Customer;
import com.paymentchange.customer.repositories.CustomerRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.web.reactive.function.client.WebClient;

@Service
public class CustomerService {

    @Autowired
    private CustomerRepository customerRepository;

    @Autowired
    private WebClient webClient;

    public Customer create(Customer customer) {
        // Validar que todos los productos existen
        for (Long productId : customer.getProductIds()) {
            Product product = webClient.get()
                .uri("/product/{id}", productId)
                .retrieve()
                .bodyToMono(Product.class)
                .block(); // Bloquea hasta obtener respuesta

            if (product == null) {
                throw new RuntimeException(
                    "Producto no encontrado: " + productId
                );
            }
        }

        // Solo guardar si todos los productos son válidos
        return customerRepository.save(customer);
    }
}

// Clase Product (DTO en Customer para recibir respuesta)
package com.paymentchange.customer.dto;

import lombok.Data;

@Data
public class Product {
    private Long id;
    private String name;
    private Double price;
}
